import{c as t}from"./app.d8523fce.js";import{_ as e}from"./plugin-vue_export-helper.21dcd24c.js";var a="/angular-security-training/assets/xss-wf.53a4e76c.png";const s={},r=t('<h1 id="_3-1-xss-overview" tabindex="-1"><a class="header-anchor" href="#_3-1-xss-overview" aria-hidden="true">#</a> 3.1 XSS Overview</h1><h2 id="xss-in-a-nutshell" tabindex="-1"><a class="header-anchor" href="#xss-in-a-nutshell" aria-hidden="true">#</a> XSS in a nutshell</h2><p>Cross-Site Scripting (XSS) is a web application vulnerability that occurs when <strong>untrusted data from the user</strong> is processed by the web application <strong>without validation</strong> and is reflected back to the browser <strong>without encoding or escaping</strong>, resulting in code execution at the browser engine.</p><p><img src="'+a+'" alt="xss-wf"></p><h2 id="why-xss-is-dangerous" tabindex="-1"><a class="header-anchor" href="#why-xss-is-dangerous" aria-hidden="true">#</a> Why XSS is dangerous ?</h2><p>The impact of XSS is moderate for reflected and DOM XSS, and severe for stored XSS, with remote code execution on the victim\u2019s browser, such as stealing credentials, sessions, MFA bypass, DOM node replacement or defacement (such as trojan login panels), key logging or delivering malware to the victim.</p><h2 id="what-causes-xss" tabindex="-1"><a class="header-anchor" href="#what-causes-xss" aria-hidden="true">#</a> What causes XSS ?</h2><p>This attack happens mostly because the web application or API uses inputs from any users within the output it generates without proper validation or encoding.</p><h2 id="how-xss-attacks-happen" tabindex="-1"><a class="header-anchor" href="#how-xss-attacks-happen" aria-hidden="true">#</a> How XSS attacks happen ?</h2><table><thead><tr><th>XSS type</th><th>Description</th><th>Payload type</th><th>Payload Examples</th><th>Real cases</th></tr></thead><tbody><tr><td>Reflected</td><td>Reflected in web server as an error message, search result or any input sent to the server as part of the request.</td><td>From request parameter.</td><td><img src="https://user-images.githubusercontent.com/1529433/174054218-bef943dc-1f60-4621-ba5f-4d4b10504111.png" alt="image"></td><td>https://www.techspot.com/news/78304-epic-games-weaknesses-check-point-hack-fortnite-accounts.html</td></tr><tr><td>Stored</td><td>Injected script is permanently stored in target servers.</td><td>Stored server-side.</td><td><img src="https://user-images.githubusercontent.com/1529433/174054511-5e9a54ef-5b8c-4b53-907a-644ecd3a147b.png" alt="image"></td><td>https://www.vice.com/en/article/wnjwb4/the-myspace-worm-that-changed-the-internet-forever</td></tr><tr><td>DOM based</td><td>Modifying the DOM environment in the victim browser.</td><td>Introduced by DOM modification.</td><td><img src="https://user-images.githubusercontent.com/1529433/174054599-3d7619d8-571c-4ada-9a05-9a7d3f3b5898.png" alt="image"></td><td>https://www.neuralegion.com/blog/dom-based-xss/</td></tr><tr><td>Mutation</td><td>Looks like safe (or just a syntax error) in itself but become active after mutation process</td><td>Mutated by browser.</td><td><img src="https://user-images.githubusercontent.com/1529433/174054791-2beee000-a47f-431f-bcac-fba3a6018e43.png" alt="image"></td><td></td></tr><tr><td>Blind Cross-Site scripting</td><td>Script is saved on server side and reflected back in the backend application.</td><td></td><td></td><td>https://samcurry.net/cracking-my-windshield-and-earning-10000-on-the-tesla-bug-bounty-program/</td></tr></tbody></table>',10);function i(n,d){return r}var h=e(s,[["render",i]]);export{h as default};
